fn solve(n: i64) -> i64 {
    // Helper function to check if a number is a palindrome
    fn is_palindrome(num: i64) -> bool {
        let mut num = num;
        let mut rev = 0;
        let mut temp = num;
        while temp > 0 {
            rev = rev * 10 + temp % 10;
            temp /= 10;
        }
        num == rev
    }

    // Helper function to check if a number meets the second condition
    fn is_valid(num: i64) -> bool {
        let mut count = std::collections::HashMap::new();
        let mut num = num;
        let mut digits = Vec::new();
        while num > 0 {
            let digit = num % 10;
            digits.push(digit);
            num /= 10;
        }
        digits.reverse();
        for &d in &digits {
            *count.entry(d).or_insert(0) += 1;
        }
        for (k, v) in &count {
            if *k != *v {
                return false;
            }
        }
        true
    }

    // Generate possible candidates in order
    let mut candidate = n + 1;
    while true {
        if is_palindrome(candidate) && is_valid(candidate) {
            return candidate;
        }
        candidate += 1;
    }
}
